// CWE-405: goroutine writes to unbuffered channel without receiver guard
package main

import "fmt"

func leaker() {
	ch := make(chan int)
	go func() {
		ch <- 42
		fmt.Println("done") // unreachable if no receiver
	}()
	// no receive — goroutine leaks
}

// Buffered channel — goroutine completes without a receiver
package main

import "fmt"

func bounded() {
	ch := make(chan int, 1)
	go func() {
		ch <- 42
		fmt.Println("done")
	}()
	v := <-ch
	fmt.Println(v)
}

// CWE-248: handler panics without defer recover
package main

import "net/http"

func handler(w http.ResponseWriter, r *http.Request) {
	if r.URL.Path == "/crash" {
		panic("boom") // unrecovered
	}
	w.Write([]byte("ok"))
}

// Recovered handler — panic caught by deferred recover
package main

import (
	"log"
	"net/http"
)

func handler(w http.ResponseWriter, r *http.Request) {
	defer func() {
		if rec := recover(); rec != nil {
			log.Printf("recovered: %v", rec)
			http.Error(w, "internal error", 500)
		}
	}()
	if r.URL.Path == "/crash" {
		panic("boom")
	}
	w.Write([]byte("ok"))
}

// CWE-704: unsafe.Pointer cast for type punning between unrelated types
package main

import "unsafe"

func punned(buf []byte) uint32 {
	return *(*uint32)(unsafe.Pointer(&buf[0]))
}

// encoding/binary — safe, portable
package main

import "encoding/binary"

func parsed(buf []byte) uint32 {
	return binary.LittleEndian.Uint32(buf)
}

