// Safe Electron defaults — nodeIntegration off, contextIsolation on
const { BrowserWindow } = require("electron");

function createWindow() {
  const win = new BrowserWindow({
    width: 800,
    height: 600,
    webPreferences: {
      nodeIntegration: false,
      contextIsolation: true,
      preload: "./preload.js",
    },
  });
  win.loadURL("https://example.com");
  return win;
}

// CWE-79: innerHTML written from req.body — XSS
function render(el, req) {
  el.innerHTML = req.body.message;
}

// Sanitized via DOMPurify — safe
import DOMPurify from "dompurify";
function render(el, req) {
  el.innerHTML = DOMPurify.sanitize(req.body.message);
}

// CWE-1321: bracket-property write keyed by req.body directly
function merge(target, req) {
  target[req.body.key] = req.body.value;
  return target;
}
module.exports = { merge };

// Guarded write — checks key against an allowlist
function merge(target, req) {
  const key = req.body.key;
  if (key === "__proto__" || key === "constructor" || key === "prototype") {
    throw new Error("forbidden key");
  }
  target[key] = req.body.value;
  return target;
}
module.exports = { merge };

